def clean_row(line):
    name, score = line.strip().split(",")
    return {"name": name.strip().title(), "score": int(score)}

records = []
with open("data/students.csv") as file:
    for line in file:
        # TODO: skip bad rows instead of printing bad row.
        try:
            records.append(clean_row(line))
        except ValueError:
            pass

print(records)

